using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            var context = new SchoolContext(options);
            return context;
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2019-09-01") },
                new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { ID = 4, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = DateTime.Parse("2019-09-01") },
                new Student { ID = 5, LastName = "Li", FirstMidName = "Yan", EnrollmentDate = DateTime.Parse("2019-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2 }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor
                {
                    ID = 10,
                    LastName = "Zheng",
                    FirstMidName = "Roger",
                    HireDate = DateTime.Parse("2004-02-12"),
                    CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
                },
                new Instructor
                {
                    ID = 11,
                    LastName = "Kapoor",
                    FirstMidName = "Candace",
                    HireDate = DateTime.Parse("2001-01-15"),
                    CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
                }
            );
            context.SaveChanges();
        }

        public static void SeedFullData(SchoolContext context)
        {
            SeedInstructors(context);
            SeedDepartments(context);

            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
            );
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = 10, CourseID = 1050 });
            context.SaveChanges();

            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2019-09-01") }
            );
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A });
            context.SaveChanges();
        }
    }
}

