using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private SchoolContext CreateContextWithStudents()
        {
            var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(context);
            return context;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_SortsByLastNameAscending_ByDefault()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Alexander", model.First().LastName);
            Assert.Equal("Li", model.Last().LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending_WhenNameDescSort()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Li", model.First().LastName);
            Assert.Equal("Alexander", model.Last().LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending_WhenDateSort()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.True(model.First().EnrollmentDate <= model.Last().EnrollmentDate);
        }

        [Fact]
        public void Index_SortsByDateDescending_WhenDateDescSort()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.True(model.First().EnrollmentDate >= model.Last().EnrollmentDate);
        }

        [Fact]
        public void Index_FiltersStudentsByLastName()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudentsByFirstName()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_ResetsPageToOne_WhenNewSearchString()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Al", 3) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // When searchString is not null, page is reset to 1
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Li", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, "test", null) as ViewResult;

            Assert.Equal("Date", controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", controller.ViewBag.DateSortParm);
            Assert.Equal("test", controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NameSortParm_IsNameDesc_WhenNoSortOrder()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_NameSortParm_IsEmpty_WhenSortOrderIsNameDesc()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            controller.Index("name_desc", null, null, null);

            Assert.Equal("", controller.ViewBag.NameSortParm);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2020-09-01"),
                Enrollments = new List<Enrollment>()
            };
            context.Students.Add(student);
            context.SaveChanges();

            var controller = new StudentsController(context);
            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewResult_WithStudentWithTodaysDate()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new StudentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_AddsStudentAndRedirects_WhenModelIsValid()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(context.Students);
            Assert.Equal("TestLast", context.Students.First().LastName);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new StudentsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
            Assert.Empty(context.Students);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateIsMinValue()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.MinValue
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateOutOfRange()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(controller.ModelState.IsValid);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithStudent()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Edit_Post_UpdatesStudentAndRedirects_WhenModelIsValid()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);
            var student = context.Students.Find(1);
            context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = 1,
                LastName = "UpdatedLast",
                FirstMidName = "UpdatedFirst",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var result = controller.Edit(updatedStudent) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                LastName = "",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenEnrollmentDateIsDefault()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = default(DateTime)
            };

            var result = controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(controller.ModelState.IsValid);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithStudent()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);
            var initialCount = context.Students.Count();

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, context.Students.Count());
        }

        #endregion
    }
}

