using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        #region SendNotification Tests

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
            var notification = service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_GeneratesCreateMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
            var notification = service.ReceiveNotification();

            Assert.Contains("New", notification.Message);
            Assert.Contains("Student", notification.Message);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_GeneratesUpdateMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Admin");
            var notification = service.ReceiveNotification();

            Assert.Contains("Course", notification.Message);
            Assert.Contains("Chemistry", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_GeneratesDeleteMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Department", "5", "Physics", EntityOperation.DELETE, "Admin");
            var notification = service.ReceiveNotification();

            Assert.Contains("Department", notification.Message);
            Assert.Contains("Physics", notification.Message);
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_UsesEntityId_WhenNoDisplayName()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");
            var notification = service.ReceiveNotification();

            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            var service = new NotificationService();
            var before = DateTime.Now;

            service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = service.ReceiveNotification();

            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now);
        }

        [Fact]
        public void SendNotification_DefaultsCreatedByToSystem()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane Smith", EntityOperation.CREATE, "Admin");
            var notification = service.ReceiveNotification();

            Assert.Contains("Jane Smith", notification.Message);
        }

        #endregion

        #region ReceiveNotification Tests

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var service = new NotificationService();

            // Drain any existing notifications from static queue
            while (service.ReceiveNotification() != null) { }

            var notification = service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNotificationsInOrder()
        {
            var service = new NotificationService();

            // Drain existing
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("A", "1", EntityOperation.CREATE);
            service.SendNotification("B", "2", EntityOperation.UPDATE);
            service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();
            var third = service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesNotificationFromQueue()
        {
            var service = new NotificationService();

            // Drain existing
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("Test", "1", EntityOperation.CREATE);
            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        #endregion

        #region MarkAsRead Tests

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var service = new NotificationService();

            // Should not throw - it's a no-op for in-memory implementation
            var exception = Record.Exception(() => service.MarkAsRead(1));

            Assert.Null(exception);
        }

        #endregion

        #region Dispose Tests

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();

            var exception = Record.Exception(() => service.Dispose());

            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();

            var exception = Record.Exception(() =>
            {
                service.Dispose();
                service.Dispose();
            });

            Assert.Null(exception);
        }

        #endregion
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        private IQueryable<int> CreateTestData(int count)
        {
            return Enumerable.Range(1, count).AsQueryable();
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_ReturnsSecondPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_ReturnsPartialLastPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.Equal(25, result.Last());
        }

        [Fact]
        public void Create_SetsPageIndex()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_CalculatesTotalPages()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void Create_CalculatesTotalPages_WhenExactMultiple()
        {
            var source = CreateTestData(20);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var source = CreateTestData(25);

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_HandlesEmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.Equal(1, result.PageIndex);
        }

        [Fact]
        public void Create_HandlesSingleItem()
        {
            var source = new[] { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result.First());
            Assert.Equal(1, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 5);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(2, list.TotalPages);
            Assert.Equal(3, list.Count);
        }
    }
}

