using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private SchoolContext CreateContextWithStudents()
        {
            var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(context);
            return context;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_SortsByLastNameAscending_ByDefault()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Alexander", model.First().LastName);
            Assert.Equal("Li", model.Last().LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending_WhenNameDescSort()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Li", model.First().LastName);
            Assert.Equal("Alexander", model.Last().LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending_WhenDateSort()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.True(model.First().EnrollmentDate <= model.Last().EnrollmentDate);
        }

        [Fact]
        public void Index_SortsByDateDescending_WhenDateDescSort()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.True(model.First().EnrollmentDate >= model.Last().EnrollmentDate);
        }

        [Fact]
        public void Index_FiltersStudentsByLastName()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudentsByFirstName()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_ResetsPageToOne_WhenNewSearchString()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Al", 3) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // When searchString is not null, page is reset to 1
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Li", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, "test", null) as ViewResult;

            Assert.Equal("Date", controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", controller.ViewBag.DateSortParm);
            Assert.Equal("test", controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NameSortParm_IsNameDesc_WhenNoSortOrder()
        {
            using var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
        }

