using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);
            _mockLogger = new Mock<ILogger<CoursesController>>();
        }

        private SchoolContext CreateContextWithCourses()
        {
            var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedCourses(context);
            return context;
        }

        private CoursesController CreateController(SchoolContext context)
        {
            return new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithListOfCourses()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewResult_WithNewCourse()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_AddsCourseAndRedirects_WhenModelIsValid()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.NotNull(context.Courses.Find(9999));
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9999, DepartmentID = 1 };

            var result = controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_SavesImage_WhenValidFileProvided()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 8888,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            var content = "fake image content";
            var ms = new MemoryStream(System.Text.Encoding.UTF8.GetBytes(content));
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(ms.Length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => ms.CopyTo(s));

            var result = controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = context.Courses.Find(8888);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_RejectsInvalidFileExtension()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 7777,
                Title = "Bad File Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("malware.exe");
            fileMock.Setup(f => f.Length).Returns(100);

            var result = controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_RejectsFileTooLarge()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 6666,
                Title = "Large File Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("large.png");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenCourseDoesNotExist()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithCourse()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_UpdatesCourseAndRedirects_WhenModelIsValid()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            // Detach existing entity
            var existing = context.Courses.Find(1050);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = controller.Edit(updatedCourse, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithCourse()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            var result = controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);
            var initialCount = context.Courses.Count();

            var result = controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_DeletesAssociatedImage()
        {
            using var context = CreateContextWithCourses();
            var controller = CreateController(context);

            // Add image path to a course
            var course = context.Courses.Find(1050);
            var uploadsPath = Path.Combine(_tempPath, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var imagePath = Path.Combine(uploadsPath, "test_image.jpg");
            File.WriteAllText(imagePath, "fake");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            context.SaveChanges();

            controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(imagePath));
        }

        #endregion
    }
}

