using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private SchoolContext CreateContextWithDepartments()
        {
            var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedInstructors(context);
            TestHelpers.SeedDepartments(context);
            return context;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithListOfDepartments()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_AddsDepartmentAndRedirects_WhenModelIsValid()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 10
            };

            var result = controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000, StartDate = DateTime.Now };

            var result = controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithDepartment()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_Post_UpdatesDepartmentAndRedirects_WhenModelIsValid()
        {
            using var context = CreateContextWithDepartments();
            var controller = new DepartmentsController(context);

            var existing = context.Departments.Find(1);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedDept = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 10
            };

