using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private SchoolContext CreateContextWithInstructors()
        {
            var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedFullData(context);
            return context;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_ShowsCoursesForSelectedInstructor()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Index(10, null) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
        }

        [Fact]
        public void Index_ShowsEnrollmentsForSelectedCourse()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Index(10, 1050) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        [Fact]
        public void Index_SetsViewBagInstructorID_WhenInstructorSelected()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            controller.Index(10, null);

            Assert.Equal(10, (int)controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_SetsViewBagCourseID_WhenCourseSelected()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            controller.Index(10, 1050);

            Assert.Equal(1050, (int)controller.ViewBag.CourseID);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithInstructor()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Zheng", model.LastName);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewResult_WithInstructor()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_AddsInstructorAndRedirects_WhenModelIsValid()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_AddsInstructorWithCourses_WhenCoursesSelected()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, new[] { "1050", "4022" }) as RedirectToActionResult;

            Assert.NotNull(result);
            var savedInstructor = context.Instructors
                .Where(i => i.LastName == "NewInstructor")
                .First();
            var assignments = context.CourseAssignments
                .Where(ca => ca.InstructorID == savedInstructor.ID);
            Assert.Equal(2, assignments.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithInstructor()
        {
            using var context = CreateContextWithInstructors();
            var controller = new InstructorsController(context);

