using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new HomeController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region About Tests

        [Fact]
        public void About_ReturnsViewResult_WithEnrollmentDateGroups()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(context);
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(context);
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // We have students with 3 different dates: 2020-09-01, 2019-09-01 (x3), 2021-09-01
            Assert.Equal(3, model.Count);
            var group2019 = model.First(g => g.EnrollmentDate == DateTime.Parse("2019-09-01"));
            Assert.Equal(3, group2019.StudentCount);
        }

        [Fact]
