using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests
    {
        #region GetNotifications Tests

        [Fact]
        public void GetNotifications_ReturnsJsonResult_WithSuccessTrue()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsEmptyList_WhenNoNotifications()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();
            var value = result.Value;

            Assert.NotNull(value);
            // Verify the result has success property
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        #endregion

        #region MarkAsRead Tests

        [Fact]
        public void MarkAsRead_ReturnsJsonResult_WithSuccessTrue()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        #endregion

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        #endregion
    }
}

